 using Microsoft.ML;
 using Microsoft.ML.Data;
 using Microsoft.Extensions.ML;

 var builder = WebApplication.CreateBuilder(args);

 // Train and save the model at startup
 var mlContext = new MLContext(seed: 42);
 var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
 var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

 var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(
     dataPath, hasHeader: true, separatorChar: ',');

 // Map "Yes"/"No" string to boolean label
 var mappingPipeline = mlContext.Transforms.CustomMapping<RawCustomerData, CustomerData>(
     (input, output) =>
     {
         output.Age = input.Age;
         output.Income = input.Income;
         output.Region = input.Region;
         output.PurchaseHistory = input.PurchaseHistory;
         output.Churned = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase);
     },
     contractName: null);

 // Load raw data first, then map
 var rawData = mlContext.Data.LoadFromTextFile<RawCustomerData>(
     dataPath, hasHeader: true, separatorChar: ',');

 var mappedData = mlContext.Transforms.CustomMapping<RawCustomerData, MappedRow>(
     (input, output) =>
     {
         output.Age = input.Age;
         output.Income = input.Income;
         output.Region = input.Region;
         output.PurchaseHistory = input.PurchaseHistory;
         output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase);
     },
     contractName: null)
     .Fit(rawData)
     .Transform(rawData);

 var split = mlContext.Data.TrainTestSplit(mappedData, testFraction: 0.2, seed: 42);

 var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
     .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

 var model = pipeline.Fit(split.TrainSet);

 // Evaluate on test set
 var predictions = model.Transform(split.TestSet);
 var metrics = mlContext.BinaryClassification.Evaluate(predictions);
 Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

 mlContext.Model.Save(model, mappedData.Schema, modelPath);

 // Register pooled prediction engine (thread-safe for ASP.NET Core)
 builder.Services.AddPredictionEnginePool<MappedRow, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<MappedRow, ChurnPrediction> pool, CustomerRequest req) =>
 {
     var input = new MappedRow
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };
     var result = pool.Predict(input);
     return Results.Ok(new
     {
         Churned = result.Churned,
         Probability = result.Probability
     });
 });

 app.Run();

 public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

