 public class RawCustomerData
 {
     [Microsoft.ML.Data.LoadColumn(0)] public float Age { get; set; }
     [Microsoft.ML.Data.LoadColumn(1)] public float Income { get; set; }
     [Microsoft.ML.Data.LoadColumn(2)] public string Region { get; set; } = "";
     [Microsoft.ML.Data.LoadColumn(3)] public float PurchaseHistory { get; set; }
     [Microsoft.ML.Data.LoadColumn(4)] public string Churned { get; set; } = "";
 }

 // Mapped row with boolean Label for ML.NET
 public class MappedRow
 {
     public float Age { get; set; }
     public float Income { get; set; }
     public string Region { get; set; } = "";
     public float PurchaseHistory { get; set; }
     public bool Label { get; set; }
 }

 public class ChurnPrediction
 {
     [ColumnName("PredictedLabel")]
